mapper.select:
SELECT COUNT(*) FROM material_order mo LEFT JOIN supplier s ON s.supplier_id = mo.supplier_id
( mo.order_id LIKE CONCAT('%', #{keyword}, '%') OR s.supplier_name LIKE CONCAT('%', #{keyword}, '%') OR EXISTS ( SELECT 1 FROM material_order_item moi2 JOIN material m2 ON m2.material_id = moi2.material_id WHERE moi2.order_id = mo.order_id AND m2.material_name LIKE CONCAT('%', #{keyword}, '%') ) )
AND mo.order_date >= #{startDate}
AND mo.order_date <= #{endDate}
AND mo.order_status = #{status}

SELECT si.supplier_id AS supplierId, si.material_id AS materialId, si.unit_price AS unitPrice, COALESCE(m.warehouse_code, 'WH001') AS warehouseCode, s.supplier_name AS supplierName, m.material_name AS materialName, -- ▼ 구매정책/단위 보강 si.min_order_qty AS minOrderQty, si.order_multiple AS orderMultiple, si.pack_qty AS packQty, si.conv_to_base AS convToBase, si.unit AS purchaseUnit FROM supplier_item si JOIN material m ON m.material_id = si.material_id JOIN supplier s ON s.supplier_id = si.supplier_id WHERE si.supply_available = 'Y' AND m.use_yn = 'Y' AND m.purchasable_flag = 'Y' AND si.material_id IN
#{materialId}
ORDER BY si.supplier_id, m.material_name

SELECT COALESCE(
	MAX(CAST(SUBSTRING_INDEX(order_item_id, '-', -1) AS UNSIGNED)), 
	0
) + 1
FROM material_order_item
WHERE order_id = #{orderId}

SELECT COALESCE(SUM(total_price),0)
FROM material_order_item
WHERE order_id = #{orderId}

SELECT COUNT(*) 
FROM material_order 
WHERE order_status = #{status}

mapper.update:
UPDATE material_order
SET order_status = #{orderStatus}
WHERE order_id = #{orderId}
